s3_client = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')
sns_client = boto3.client('sns')
sqs_client = boto3.client('sqs')

BUCKET_NAME = os.environ.get('S3_BUCKET_NAME', f"microservices-data-bucket-{boto3.client('sts').get_caller_identity()['Account']}")
TABLE_NAME = os.environ.get('DYNAMODB_TABLE_NAME', 'microservices-data')
SNS_TOPIC_ARN = os.environ.get('SNS_TOPIC_ARN', '')
SQS_QUEUE_URL = os.environ.get('SQS_QUEUE_URL', '')


def lambda_handler(event, context):
    try:
        operation = event.get('operation', 'process')
        
        if operation == 'process':
            result = process_data(event.get('data', {}))
        elif operation == 's3_upload':
            result = upload_to_s3(event.get('key'), event.get('content'))
        elif operation == 'dynamodb_write':
            result = write_to_dynamodb(event.get('item'))
        elif operation == 'sns_publish':
            result = publish_to_sns(event.get('message'))
        elif operation == 'sqs_send':
            result = send_to_sqs(event.get('message'))
        else:
            result = {'error': 'Unknown operation'}
        
        return {
            'statusCode': 200,
            'body': json.dumps(result),
            'headers': {
                'Content-Type': 'application/json',
                'X-Content-Type-Options': 'nosniff',
                'Strict-Transport-Security': 'max-age=31536000; includeSubDomains'
            }
        }
    
    except ClientError as e:
        print(f"AWS Client Error: {str(e)}")
        return {
            'statusCode': 500,
            'body': json.dumps({'error': 'Service error occurred'}),
            'headers': {'Content-Type': 'application/json'}
        }
    except Exception as e:
        print(f"Error: {str(e)}")
        return {
            'statusCode': 500,
            'body': json.dumps({'error': 'Internal server error'}),
            'headers': {'Content-Type': 'application/json'}
        }


def process_data(data):
    return {
        'message': 'Data processed successfully',
        'data': data
    }


def upload_to_s3(key, content):
    if not key or not content:
        raise ValueError("Key and content are required")
    
    s3_client.put_object(
        Bucket=BUCKET_NAME,
        Key=key,
        Body=content,
        ServerSideEncryption='AES256'
    )
    
    return {
        'message': 'File uploaded successfully',
        'bucket': BUCKET_NAME,
        'key': key
    }


def write_to_dynamodb(item):
    if not item or 'id' not in item:
        raise ValueError("Item with 'id' is required")
    
    table = dynamodb.Table(TABLE_NAME)
    table.put_item(Item=item)
    
    return {
        'message': 'Item written successfully',
        'item_id': item['id']
    }


def publish_to_sns(message):
    if not message or not SNS_TOPIC_ARN:
        raise ValueError("Message and SNS topic ARN are required")
    
    response = sns_client.publish(
        TopicArn=SNS_TOPIC_ARN,
        Message=json.dumps(message),
        Subject='Microservice Notification'
    )
    
    return {
        'message': 'Message published successfully',
        'message_id': response['MessageId']
    }


def send_to_sqs(message):
    if not message or not SQS_QUEUE_URL:
        raise ValueError("Message and SQS queue URL are required")
    
    response = sqs_client.send_message(
        QueueUrl=SQS_QUEUE_URL,
        MessageBody=json.dumps(message)
    )
    
    return {
        'message': 'Message sent successfully',
        'message_id': response['MessageId']
    }